INSERT INTO homepage_banners (title, subtitle, eyebrow, cta_label, cta_url, image_path, sort_order, is_active) VALUES ('Trade in your old phone','Get a better phone with a smarter upgrade path. Ask support about device assessment before checkout.','Upgrade Program','Start Assessment','support.php','assets/images/apple-iphone-15.svg',1,1);
INSERT INTO homepage_banners (title, subtitle, eyebrow, cta_label, cta_url, image_path, sort_order, is_active) VALUES ('Student-ready phone bundles','Phones, chargers, cases, and earbuds prepared for daily university life in Turkey.','Bundle Deals','Shop Accessories','products.php?category=accessories','assets/images/apple-airpods-pro-usb-c.svg',2,1);
INSERT INTO support_faqs (question, answer, category, sort_order, is_active) VALUES ('How long does phone delivery take in Turkey?','In-stock phone orders are usually prepared within 1 business day. Delivery timing depends on the city and selected shipping method.','Shipping',1,1);
INSERT INTO support_faqs (question, answer, category, sort_order, is_active) VALUES ('Are the phones covered by warranty?','Each product page should clearly show its warranty status. Prefer official distributor warranty items when you need full local service confidence.','Warranty',2,1);
INSERT INTO support_faqs (question, answer, category, sort_order, is_active) VALUES ('Can customers pay by card or installment?','The checkout flow supports the active payment methods configured in the admin panel. Use the product and payment settings to communicate installment options clearly.','Payments',3,1);
INSERT INTO support_faqs (question, answer, category, sort_order, is_active) VALUES ('Can a phone be returned?','Returns depend on the return policy and product condition. Keep the original box, accessories, and invoice for any return or service request.','Returns',4,1);
